        """Retrieves an order by its ID."""
        try:
            return self.session.query(Order).filter_by(id=order_id).first()
        except Exception as e:
            print(f"Error getting order by ID: {e}")
            return None

    def search_bicycles(self, search_term):
        """Searches for bicycles by name or description."""
        try:
            return self.session.query(Bicycle).filter(
                sqlalchemy.or_(
                    Bicycle.name.ilike(f"%{search_term}%"),
                    Bicycle.description.ilike(f"%{search_term}%")
                )
            ).all()
        except Exception as e:
            print(f"Error searching bicycles: {e}")
