    def create_order(self, customer_id, items):
        """Creates a new order with the given items."""
        try:
            customer = self.get_customer_by_id(customer_id)
            if not customer:
                print("Customer not found.")
                return False

            new_order = Order(customer=customer)
            total_amount = 0.0

            for item in items:
                item_type = item.get('type')
                item_id = item.get('id')
                quantity = item.get('quantity')

                if item_type == 'bicycle':
                    bicycle = self.get_bicycle_by_id(item_id)
                    if not bicycle:
                        print(f"Bicycle with ID {item_id} not found.")
                        self.session.rollback()
                        return False

                    if bicycle.stock_quantity < quantity:
                        print(f"Not enough stock for bicycle {bicycle.name}.")
                        self.session.rollback()
                        return False

                    order_item = OrderItem(order=new_order, bicycle=bicycle, quantity=quantity, unit_price=bicycle.price)
                    bicycle.stock_quantity -= quantity
                    total_amount += bicycle.price * quantity

                elif item_type == 'part':
                    part = self.get_part_by_id(item_id)
                    if not part:
                        print(f"Part with ID {item_id} not found.")
                        self.session.rollback()
                        return False

                    if part.stock_quantity < quantity:
                        print(f"Not enough stock for part {part.name}.")
                        self.session.rollback()
                        return False

                    order_item = OrderItem(order=new_order, part=part, quantity=quantity, unit_price=part.price)
                    part.stock_quantity -= quantity
                    total_amount += part.price * quantity
                else:
                    print(f"Invalid item type: {item_type}")
                    self.session.rollback()
                    return False

                self.session.add(order_item)

            new_order.total_amount = total_amount
            self.session.add(new_order)
            self.session.commit()
            return True

        except Exception as e:
            self.session.rollback()
            print(f"Error creating order: {e}")
            return False

    def update_stock_quantity(self, item_type, item_id, new_quantity):
        """Updates the stock quantity of a bicycle or part."""
        try:
            if item_type == 'bicycle':
                bicycle = self.get_bicycle_by_id(item_id)
                if not bicycle:
                    print(f"Bicycle with ID {item_id} not found.")
                    return False
                bicycle.stock_quantity = new_quantity
            elif item_type == 'part':
                part = self.get_part_by_id(item_id)
                if not part:
                    print(f"Part with ID {item_id} not found.")
                    return False
                part.stock_quantity = new_quantity
            else:
                print(f"Invalid item type: {item_type}")
                return False

            self.session.commit()
            return True
        except Exception as e:
            self.session.rollback()
            print(f"Error updating stock quantity: {e}")
            return False


