    def add_order_item(self, order_id, product_id, quantity, price_per_item):
        order_item = OrderItem(order_id=order_id, product_id=product_id, quantity=quantity, price_per_item=price_per_item)
        self.session.add(order_item)

        order = self.get_order(order_id)
        product = self.get_product(product_id)

        if order and product:
            order.total_amount += quantity * price_per_item
            product.stock_quantity -= quantity

        self.session.commit()
        return order_item

    def get_order_item(self, order_item_id):
        return self.session.query(OrderItem).get(order_item_id)

    def update_order_item(self, order_item_id, quantity=None, price_per_item=None):
        order_item = self.get_order_item(order_item_id)
        if order_item:
            order = self.get_order(order_item.order_id)
            product = self.get_product(order_item.product_id)

            if order and product:
                order.total_amount -= order_item.quantity * order_item.price_per_item

                if quantity:
                    product.stock_quantity += (order_item.quantity - quantity)
                    order_item.quantity = quantity
                if price_per_item:
                    order_item.price_per_item = price_per_item

                order.total_amount += order_item.quantity * order_item.price_per_item

            self.session.commit()
            return True
        return False

    def delete_order_item(self, order_item_id):
        order_item = self.get_order_item(order_item_id)
        if order_item:
            order = self.get_order(order_item.order_id)
            product = self.get_product(order_item.product_id)

            if order and product:
                order.total_amount -= order_item.quantity * order_item.price_per_item
                product.stock_quantity += order_item.quantity

            self.session.delete(order_item)
            self.session.commit()
